-- 0013_dhamas.sql — дхамы/тиртхи в D1 со связями:
--   тиртха→дхама (FK), тиртха→кластер, тиртха→личность (tirtha_persons FK на entities),
--   дхама→первичное Божество (FK). Источник: apps/web/src/dhama/dhamas.ts. См. docs/PASSPORT.md §B-3.
DROP TABLE IF EXISTS tirtha_persons;
DROP TABLE IF EXISTS tirthas;
DROP TABLE IF EXISTS dhama_clusters;
DROP TABLE IF EXISTS dhamas;
CREATE TABLE dhamas (
  id TEXT PRIMARY KEY, name TEXT NOT NULL, iast TEXT, tagline TEXT,
  deity TEXT, deity_entity_id TEXT REFERENCES entities(id),
  region TEXT, hero TEXT, accent TEXT,
  center_lat REAL, center_lng REAL, center_zoom REAL,
  intro TEXT, facts TEXT, sort INTEGER NOT NULL DEFAULT 0
);
CREATE TABLE dhama_clusters (
  dhama_id TEXT NOT NULL REFERENCES dhamas(id), cluster_id TEXT NOT NULL,
  title TEXT NOT NULL, note TEXT, sort INTEGER NOT NULL DEFAULT 0,
  PRIMARY KEY (dhama_id, cluster_id)
);
CREATE TABLE tirthas (
  id TEXT PRIMARY KEY, dhama_id TEXT NOT NULL REFERENCES dhamas(id), cluster TEXT NOT NULL,
  name TEXT NOT NULL, iast TEXT, kind TEXT NOT NULL,
  lat REAL, lng REAL, blurb TEXT, about TEXT, lila TEXT,
  persons TEXT, maps TEXT, source TEXT, sort INTEGER NOT NULL DEFAULT 0
);
CREATE TABLE tirtha_persons (
  tirtha_id TEXT NOT NULL REFERENCES tirthas(id), entity_id TEXT REFERENCES entities(id),
  name TEXT NOT NULL, q TEXT, sort INTEGER NOT NULL DEFAULT 0
);
CREATE INDEX idx_tirthas_dhama ON tirthas(dhama_id, cluster, sort);
CREATE INDEX idx_tirtha_persons_tirtha ON tirtha_persons(tirtha_id);
CREATE INDEX idx_tirtha_persons_entity ON tirtha_persons(entity_id);
