INSERT INTO dhamas (id,name,iast,tagline,deity,deity_entity_id,region,hero,accent,center_lat,center_lng,center_zoom,intro,facts,sort) VALUES
('vrindavan','Вриндаван','Vṛndāvana','Земля сладостных игр Шри Кришны','Шри Шри Радха-Кришна','krishna','Уттар-Прадеш, Индия','/media/vrindavan.webp','#1E8E5B',27.55,77.58,11,'["Вриндаван — сердце Враджа-мандалы, земли в восемьдесят четыре кроши вокруг Матхуры, где пять тысяч лет назад Верховный Господь Шри Кришна явил Свои самые сокровенные и нежные игры. Это не обычное географическое место: согласно вайшнавским писаниям, Вриндаван неотличен от духовного мира и вечно пребывает в сердце Господа.", "Здесь Кришна рос пастушком, пас коров вместе с друзьями, побеждал демонов, поднял холм Говардхана и танцевал раса-лилу с гопи. Каждая роща, каждый водоём и каждый холм Враджа хранит память о конкретной игре Господа и Его вечных спутников.", "В XVI веке по указанию Шри Чайтаньи Махапрабху шесть Госвами Вриндавана раскрыли утраченные святые места, установили божества и составили писания, восстановив славу дхамы. Их труды и сегодня ведут паломников по тропам Враджа."]','[{"k": "Также", "v": "Враджа-мандала"}, {"k": "Главные игры", "v": "Раса-лила, Говардхана, детство Кришны"}, {"k": "Размер", "v": "84 кроши (~268 км в окружности)"}, {"k": "Парикрама", "v": "Враджа-мандала-парикрама"}]',0),
('navadvipa','Навадвипа','Navadvīpa','Девять островов явления Шри Чайтаньи','Шри Шри Гаура-Нитай','chaitanya','Западная Бенгалия, Индия','/media/mayapur.webp','#C9962B',23.42,88.38,12,'["Навадвипа-дхама — святая земля на берегах Ганги, где пятьсот лет назад явился Гауранга Махапрабху, Сам Кришна в облике Своего преданного, чтобы раздать миру любовь к Богу через совместное пение святых имён.", "«Навадвипа» означает «девять островов»; согласно «Навадвипа-дхама-махатмье» Бхактивиноды Тхакура, девять островов олицетворяют девять видов преданного служения — слушание, воспевание, памятование и прочие. Сама дхама в форме восьмилепесткового лотоса неотлична от Шри Вриндавана.", "В сердце дхамы — Маяпур, Антардвипа, где в Йогапитхе родился Господь Гауранга. Сегодня здесь стоит всемирная штаб-квартира ИСККОН с величественным Храмом Ведического Планетария (TOVP)."]','[{"k": "Также", "v": "Гаура-мандала, Шридхама Маяпур"}, {"k": "Главные игры", "v": "Явление и санкиртана Шри Чайтаньи"}, {"k": "Девять островов", "v": "НавадхА бхакти — девять видов служения"}, {"k": "Парикрама", "v": "Навадвипа-мандала-парикрама"}]',1),
('nilachala','Нилачала','Nīlācala','Обитель Господа Джаганнатхи','Шри Шри Джаганнатха, Баладева, Субхадра',NULL,'Джаганнатха-Пури, Одиша, Индия',NULL,'#3457C4',19.805,85.825,14,'["Нилачала, «Синяя гора», — святой город Джаганнатха-Пури на берегу Бенгальского залива, одна из четырёх главных дхам Индии. Здесь Господь Кришна являет Себя как Джаганнатха, «Владыка вселенной», вместе с братом Баладевой и сестрой Субхадрой.", "Пури — место, где последние восемнадцать лет Своих игр провёл Шри Кришна Чайтанья Махапрабху, погружённый в высшие переживания любви в разлуке в настроении Шримати Радхарани. Сюда к Нему стекались преданные со всей Индии.", "Знаменитая Ратха-ятра — праздник колесниц — воспроизводит возвращение Кришны во Вриндаван: Джаганнатху везут из Его храма в Гундичу, что олицетворяет встречу с жителями Враджа после долгой разлуки."]','[{"k": "Также", "v": "Джаганнатха-Пури, Пурушоттама-кшетра"}, {"k": "Божества", "v": "Джаганнатха, Баладева, Субхадра"}, {"k": "Главная игра", "v": "18 лет игр Шри Чайтаньи; Ратха-ятра"}, {"k": "Дхама", "v": "Одна из четырёх дхам Индии"}]',2);
