INSERT INTO tirthas (id,dhama_id,cluster,name,iast,kind,lat,lng,blurb,about,lila,persons,maps,source,sort) VALUES
('krishna-janmasthan','vrindavan','mathura','Шри Кришна-Джанмастхан','Kṛṣṇa Janmasthāna','temple',27.505,77.668,'Темница, где явился Господь Кришна','Место явления Шри Кришны — тюремная камера во дворце Камсы, где томились Васудева и Деваки. Над святыней стоит храм Кешава-дева; рядом — символическая темница с божествами родителей Господа.','В полночь месяца бхадра Кришна явился как четырёхрукий Вишну, а затем принял облик младенца. По наставлению Господа Васудева перенёс Его через разлившуюся Ямуну в Гокулу, к Нанде и Яшоде.','[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Васудева", "q": "Васудева"}, {"name": "Деваки", "q": "Деваки"}, {"name": "Камса", "q": "Камса"}]','Krishna Janmasthan Mathura',NULL,0),
('vishram-ghat','vrindavan','mathura','Вишрама-гхат','Viśrāma Ghāṭa','ghat',27.511,77.684,'Кришна отдыхал здесь после убийства Камсы','Главный гхат Матхуры на берегу Ямуны. Здесь Кришна и Баларама омылись и отдохнули после освобождения Матхуры от тирании Камсы.','Сразив Камсу на арене, Кришна освободил Своих родителей и деда Уграсену, вернув ему трон, и отдохнул на этом берегу.','[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Господь Баларама", "q": "Баларама"}, {"name": "Камса", "q": "Камса"}]','Vishram Ghat Mathura',NULL,1),
('dwarkadhish-mathura','vrindavan','mathura','Храм Дваркадхиша','Dvārkādhīśa Mandira','temple',27.5118,77.6826,'Главный храм современной Матхуры','Величественный храм в центре старого города, где поклоняются Кришне в образе Дваркадхиша — повелителя Двараки. Один из самых посещаемых храмов Матхуры.',NULL,'[{"name": "Шри Кришна", "q": "Кришна"}]','Dwarkadhish Temple Mathura',NULL,2),
('gokula','vrindavan','gokula','Гокула (Махаван)','Gokula','village',27.443,77.724,'Дом Нанды, где прошло младенчество Кришны','Селение на берегу Ямуны, куда Васудева тайно принёс новорождённого Кришну. Здесь, в доме Нанды Махараджи, Господь провёл первые годы и явил игры младенчества. Сохранился древний двор Чаураси-кхамба («восемьдесят четыре колонны»).','В Гокуле Кришна сразил ведьму Путану, опрокинул телегу (Шаката-бхаджана), был унесён вихрем-демоном Тринавартой и явил матери Яшоде вселенную в Своих устах.','[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Нанда Махараджа", "q": "Нанда Махараджа"}, {"name": "Матушка Яшода", "q": "Яшода"}, {"name": "Рохини", "q": "Рохини"}, {"name": "Путана", "q": "Путана"}]','Gokul Mahavan Mathura',NULL,3),
('raman-reti','vrindavan','gokula','Рамана-рети','Ramaṇa Reti','place',27.436,77.718,'Мягкие пески, где играли Кришна и Баларама','Полоса мягкого белого песка близ Гокулы, где маленькие Кришна и Баларама резвились и ползали в детстве. Паломники катаются по этому песку, считая его освящённым прикосновением Господа.','Здесь братья учились ходить, играли с телятами и друзьями-пастушками под присмотром Яшоды и Рохини.','[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Господь Баларама", "q": "Баларама"}, {"name": "Матушка Яшода", "q": "Яшода"}]','Raman Reti Gokul',NULL,4),
('seva-kunja','vrindavan','town','Сева-кунджа','Sevā Kuñja','forest',27.583,77.7,'Роща ночной раса-лилы Радхи и Кришны','Сокровенная роща в центре Вриндавана, где Радха и Кришна встречаются по ночам. Считается, что и сегодня здесь происходят вечные игры, поэтому на ночь рощу закрывают для людей.','В Сева-кундже Кришна служил Шримати Радхарани, украшая Её и поправляя Её причёску, а гопи погружались в нектар према-расы.','[{"name": "Шримати Радхарани", "q": "Радхарани"}, {"name": "Шри Кришна", "q": "Кришна"}, {"name": "Лалита-сакхи", "q": "Лалита"}, {"name": "Вишакха-сакхи", "q": "Вишакха"}]','Seva Kunj Vrindavan',NULL,5),
('nidhuvan','vrindavan','town','Нидхуван','Nidhuvana','forest',27.5856,77.7011,'Густая роща сокровенных игр','Тенистая роща переплетённых деревьев тулси, где, по преданию, и поныне проходит ночная раса-лила. Здесь явил себя Свами Харидас, наставник в музыке, чьим пением Кришна был привлечён в образе Банке Бихари.',NULL,'[{"name": "Шримати Радхарани", "q": "Радхарани"}, {"name": "Шри Кришна", "q": "Кришна"}]','Nidhivan Vrindavan',NULL,6),
('banke-bihari','vrindavan','town','Храм Банке-Бихари','Bāṅke Bihārī Mandira','temple',27.5847,77.6998,'Самовозникшее божество, явленное Свами Харидасом','Один из самых любимых храмов Вриндавана. Божество Банке Бихари («изогнутый в трёх местах») столь могущественно, что занавес перед Ним то открывают, то закрывают, чтобы паломник не лишился чувств от Его взгляда.','Божество явилось в Нидхуване в ответ на молитвы и пение Свами Харидаса, соединив в одном образе Радху и Кришну.','[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Шримати Радхарани", "q": "Радхарани"}]','Banke Bihari Temple Vrindavan',NULL,7),
('radha-raman','vrindavan','town','Храм Радха-Рамана','Rādhā-Ramaṇa Mandira','temple',27.5817,77.7015,'Самопроявившееся божество Гопалы Бхатты Госвами','Храм самопроявившегося божества Радха-Рамана, возникшего из шалаграма-шилы Гопалы Бхатты Госвами. Здесь до сих пор хранят неугасимый огонь, зажжённый при установлении божества почти пять веков назад.','В ночь полнолуния Гопала Бхатта молился о форме Господа, которой можно служить; наутро одна из его шалаграм явилась как прекрасное мурти Кришны.','[{"name": "Гопала Бхатта Госвами", "q": "Гопала Бхатта"}, {"name": "Шри Кришна", "q": "Кришна"}]','Radha Raman Temple Vrindavan',NULL,8),
('radha-damodara','vrindavan','town','Храм Радха-Дамодара','Rādhā-Dāmodara Mandira','temple',27.5805,77.7032,'Самадхи Рупы Госвами; бхаджан Шрилы Прабхупады','Храм, основанный Дживой Госвами, хранит самадхи Рупы Госвами и говардхана-шилу с отпечатком стопы Кришны, данную Самим Господом Рагхунатхе дасу. В этих покоях Шрила Прабхупада несколько лет работал над переводом «Чайтанья-чаритамриты» перед отъездом на Запад.',NULL,'[{"name": "Рупа Госвами", "q": "Рупа Госвами"}, {"name": "Джива Госвами", "q": "Джива Госвами"}, {"name": "Рагхунатха дас Госвами", "q": "Рагхунатха дас"}, {"name": "Шрила Прабхупада", "q": "Прабхупада"}]','Radha Damodar Temple Vrindavan',NULL,9),
('govindaji','vrindavan','town','Храм Радха-Говинда-дева','Govinda-deva Mandira','temple',27.591,77.694,'Древний семиэтажный храм Рупы Госвами','Грандиозный храм красного песчаника, построенный для божества Говинда-дева, которое раскопал Рупа Госвами. Возведён в XVI веке Махараджей Ман Сингхом; некогда возвышался на семь этажей, пока не был разрушен Аурангзебом.','Божество Говинды было установлено правнуком Кришны Ваджрой и спустя века вновь явлено Рупой Госвами на холме Гома-тила.','[{"name": "Рупа Госвами", "q": "Рупа Госвами"}, {"name": "Шри Кришна", "q": "Кришна"}]','Govind Dev Ji Temple Vrindavan',NULL,10),
('madana-mohana','vrindavan','town','Храм Мадана-Мохана','Madana-Mohana Mandira','temple',27.5882,77.6868,'Старейший храм Вриндавана на холме у Ямуны','Один из древнейших храмов Враджа, стоящий на холме Двадашадитья у Ямуны. Здесь служил Санатана Госвами, старший из шести Госвами; божество Мадана-Мохана раскрывает сокровенную связь любви с Господом.',NULL,'[{"name": "Санатана Госвами", "q": "Санатана Госвами"}, {"name": "Шри Кришна", "q": "Кришна"}]','Madan Mohan Temple Vrindavan',NULL,11),
('imli-tala','vrindavan','town','Имли-тала','Imli-talā','place',27.579,77.708,'Тамариндовое дерево, под которым тосковал Кришна','Древнее тамариндовое дерево на берегу Ямуны. Под ним Кришна сидел, погружённый в мысли о Шримати Радхарани, и Его тело приняло золотистый оттенок Её любви. Спустя века здесь медитировал Гауранга Махапрабху.','После ухода гопи в разгар раса-лилы Кришна, охваченный разлукой, пришёл сюда и принял настроение Радхи — то самое, что позже воплотил Гауранга Махапрабху.','[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Шримати Радхарани", "q": "Радхарани"}, {"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Imli Tala Vrindavan',NULL,12),
('keshi-ghat','vrindavan','town','Кеши-гхат','Keśī Ghāṭa','ghat',27.5876,77.7045,'Кришна омылся здесь, сразив демона-коня Кеши','Прекраснейший гхат Вриндавана на изгибе Ямуны. Здесь Кришна искупался после того, как убил демона Кеши, явившегося в облике свирепого коня. Вечерняя арати Ямуне на этом гхате — одно из самых возвышенных переживаний Враджа.','Демон Кеши, посланный Камсой, напал на Вриндаван конём; Кришна вонзил руку ему в пасть и сразил его, получив имя Кешава.','[{"name": "Шри Кришна", "q": "Кришна"}]','Keshi Ghat Vrindavan',NULL,13),
('vamshi-vata','vrindavan','town','Вамши-вата','Vaṁśī-vaṭa','place',27.5862,77.7058,'Баньян, под которым Кришна звал гопи флейтой','Баньяновое дерево на берегу Ямуны, под которым Кришна играл на флейте. Звук вамши разносился по Враджу и призывал гопи на раса-лилу.','В осеннюю ночь полнолуния Кришна заиграл на флейте под этим деревом; зачарованные гопи оставили дома и устремились к Нему для танца раса.','[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Шримати Радхарани", "q": "Радхарани"}, {"name": "Лалита-сакхи", "q": "Лалита"}]','Vamshi Vat Vrindavan',NULL,14),
('chira-ghat','vrindavan','town','Чира-гхат','Cīra Ghāṭa','ghat',27.59,77.702,'Кришна забрал одежды купающихся гопи','Гхат на Ямуне, где Кришна забрал одежды юных гопи, дав им урок смирения и преданности. Это игра вастра-хараны, раскрывающая полную отдачу души Господу.',NULL,'[{"name": "Шри Кришна", "q": "Кришна"}]','Chir Ghat Vrindavan',NULL,15),
('krishna-balaram-mandir','vrindavan','town','Кришна-Баларам мандир (ИСККОН)','Kṛṣṇa-Balarāma Mandira','temple',27.5778,77.6997,'Храм ИСККОН и самадхи Шрилы Прабхупады','Храм, основанный Шрилой Прабхупадой в Рамана-рети, где Кришна и Баларама играли в детстве. Здесь поклоняются Кришне-Балараме, Радха-Шьямасундаре и Гаура-Нитаю; во дворе — мраморное самадхи-мандир Шрилы Прабхупады.',NULL,'[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Господь Баларама", "q": "Баларама"}, {"name": "Шрила Прабхупада", "q": "Прабхупада"}]','Krishna Balaram Mandir Vrindavan',NULL,16),
('govardhana-hill','vrindavan','govardhana','Холм Говардхана','Govardhana','hill',27.499,77.459,'Холм, который Кришна поднял на мизинце','Священный холм, которому поклоняются как самому Кришне (Гиридхари). Паломники обходят его по парикраме в 21 км, не ступая на сам холм из почтения. Здесь — Дана-гхати, Мукхаравинда, Манаси-ганга и Говинда-кунда.','Когда Кришна остановил жертвоприношение Индре, разгневанный царь небес наслал потоп; Кришна семь дней держал холм на мизинце, укрывая жителей Враджа, и Индра смирился.','[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Господь Баларама", "q": "Баларама"}, {"name": "Нанда Махараджа", "q": "Нанда Махараджа"}]','Govardhan Hill Mathura',NULL,17),
('manasi-ganga','vrindavan','govardhana','Манаси-ганга','Mānasī Gaṅgā','kunda',27.497,77.462,'Ганга, явленная Кришной силой мысли','Большое озеро у подножия Говардханы. Кришна явил здесь Гангу из Своего ума, чтобы очистить Нанду Махараджу, и поныне на воде совершают вечернюю дипа-дану — пускают огоньки светильников.',NULL,'[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Нанда Махараджа", "q": "Нанда Махараджа"}]','Manasi Ganga Govardhan',NULL,18),
('kusum-sarovara','vrindavan','govardhana','Кусума-саровара','Kusuma-sarovara','kunda',27.524,77.476,'Озеро, где Радха собирала цветы','Прекрасное озеро в обрамлении резных кенотафов из песчаника. Сюда Шримати Радхарани с подругами приходила собирать цветы, и здесь Её встречал Кришна.',NULL,'[{"name": "Шримати Радхарани", "q": "Радхарани"}, {"name": "Шри Кришна", "q": "Кришна"}, {"name": "Лалита-сакхи", "q": "Лалита"}]','Kusum Sarovar Govardhan',NULL,19),
('danaghati','vrindavan','govardhana','Дана-гхати','Dāna-ghāṭī','place',27.493,77.466,'Кришна взимал «пошлину» с гопи','Узкий проход у Говардханы, где Кришна с друзьями в шутку преграждал путь гопи, несущим масло и молоко, требуя «дань» (дана). Игра дана-лилы полна остроумных любовных перепалок.',NULL,'[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Шримати Радхарани", "q": "Радхарани"}]','Daan Ghati Mandir Govardhan',NULL,20),
('radha-kunda','vrindavan','radhakunda','Радха-кунда','Rādhā-kuṇḍa','kunda',27.523,77.443,'Высшее святое место — пруд любви Радхи','По словам Госвами, Радха-кунда — наивысшая из всех тиртх, ибо она неотлична от Самой Шримати Радхарани. Рядом — Шьяма-кунда Кришны. Здесь жили и совершали бхаджан Рупа, Санатана и Рагхунатха дас Госвами.','Убив демона-быка Аришту, Кришна, по слову гопи, искупил «грех» убийства, ударив пяткой о землю и призвав святые воды; Радха со спутницами выкопала рядом Свою кунду браслетами.','[{"name": "Шримати Радхарани", "q": "Радхарани"}, {"name": "Шри Кришна", "q": "Кришна"}, {"name": "Рагхунатха дас Госвами", "q": "Рагхунатха дас"}, {"name": "Рупа Госвами", "q": "Рупа Госвами"}]','Radha Kunda Govardhan',NULL,21),
('shyama-kunda','vrindavan','radhakunda','Шьяма-кунда','Śyāma-kuṇḍa','kunda',27.5224,77.4438,'Пруд Кришны рядом с Радха-кундой','Кунда, явленная Кришной после убийства Аришты. Шьяма-кунда и Радха-кунда — две соприкасающиеся святыни, олицетворяющие нераздельную любовь Божественной Четы.',NULL,'[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Шримати Радхарани", "q": "Радхарани"}]','Shyama Kunda Radha Kunda',NULL,22),
('shriji-mandir','vrindavan','barsana','Шриджи мандир (Ладли Лал)','Śrījī Mandira','temple',27.648,77.376,'Храм Шримати Радхарани на вершине холма Барсаны','Главный храм Барсаны, венчающий холм Брахма-парвата, где поклоняются Шримати Радхарани как Ладли-джи. Барсана знаменита праздником Латхмар-холи, когда гопи Барсаны «прогоняют» палками пастушков Нандаграма.','Здесь, в доме Вришабхану и Киртиды, явилась Шримати Радхарани — олицетворение энергии наслаждения Господа.','[{"name": "Шримати Радхарани", "q": "Радхарани"}, {"name": "Вришабхану", "q": "Вришабхану"}, {"name": "Киртида", "q": "Киртида"}]','Shriji Temple Barsana',NULL,23),
('man-mandir-barsana','vrindavan','barsana','Мана-мандир','Māna Mandira','place',27.646,77.374,'Пещера, где Радха выражала любовную обиду','Уединённый грот на склоне Барсаны, где Шримати Радхарани удалялась в мана — любовную обиду, а Кришна и подруги старались Её утешить. Игры маны раскрывают высшие глубины премы.',NULL,'[{"name": "Шримати Радхарани", "q": "Радхарани"}, {"name": "Шри Кришна", "q": "Кришна"}, {"name": "Лалита-сакхи", "q": "Лалита"}]','Maan Mandir Barsana',NULL,24),
('nanda-bhavan','vrindavan','nandagaon','Нанда-Бхавана','Nanda Bhavana','temple',27.717,77.387,'Дом Нанды Махараджи на холме Нандишвара','Храм на вершине холма Нандишвара, где стоял дом Нанды Махараджи. Отсюда подросший Кришна вместе с Баларамой и друзьями ежедневно уводил коров на пастбища Враджа.','В Нандаграме разворачивались игры родительской любви (ватсалья) Нанды и Яшоды и дружбы Кришны с пастушками — Шридамой, Субалой и другими.','[{"name": "Нанда Махараджа", "q": "Нанда Махараджа"}, {"name": "Матушка Яшода", "q": "Яшода"}, {"name": "Шри Кришна", "q": "Кришна"}, {"name": "Господь Баларама", "q": "Баларама"}]','Nand Bhavan Nandgaon',NULL,25),
('pavana-sarovara','vrindavan','nandagaon','Павана-саровара','Pāvana-sarovara','kunda',27.715,77.389,'Озеро, где Яшода купала Кришну','Тихое озеро у подножия Нандишвары. Здесь матушка Яшода омывала маленького Кришну, а пастушки купали стада. Поэт Рагхунатха дас называл его одним из любимых мест Господа.',NULL,'[{"name": "Матушка Яшода", "q": "Яшода"}, {"name": "Шри Кришна", "q": "Кришна"}]','Pavan Sarovar Nandgaon',NULL,26),
('bhandiravan','vrindavan','vana','Бхандираван','Bhāṇḍīravana','forest',27.47,77.65,'Лес Баларамы и огромного баньяна','Лес на берегу Ямуны со знаменитым древним баньяном Бхандира. Здесь Баларама сразил демона Праламбу, а по преданию состоялась тайная свадьба Радхи и Кришны в присутствии Брахмы.','Демон Праламба, проникший к пастушкам, понёс Балараму на спине; Господь могучим ударом кулака сразил его.','[{"name": "Господь Баларама", "q": "Баларама"}, {"name": "Шри Кришна", "q": "Кришна"}, {"name": "Шримати Радхарани", "q": "Радхарани"}]','Bhandirvan Mathura',NULL,27),
('madhuvan','vrindavan','vana','Мадхуван','Madhuvana','forest',27.464,77.636,'Первый из двенадцати лесов Враджа','Один из двенадцати лесов Враджа, связанный с играми Кришны и пастушков. Здесь же находится Дхрува-тила, где, по преданию, юный Дхрува совершал суровую аскезу.',NULL,'[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Господь Баларама", "q": "Баларама"}]','Madhuban Mathura',NULL,28),
('kokilavan','vrindavan','vana','Кокилаван','Kokilāvana','forest',27.69,77.43,'Роща, где Кришна куковал кукушкой','Тихая лесная роща, где Кришна подражал пению кукушки (кокила), подзывая Радху и подруг. Здесь же чтят Шани-дева, получившего милость лицезреть Господа.',NULL,'[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Шримати Радхарани", "q": "Радхарани"}]','Kokilavan Dham Kosi',NULL,29),
('akrura-ghat','vrindavan','vana','Акрура-гхат','Akrūra Ghāṭa','ghat',27.53,77.67,'Акруре открылось видение духовного мира','Гхат на пути из Вриндавана в Матхуру. Когда Акрура вёз Кришну и Балараму к Камсе, он окунулся в Ямуну и узрел в воде Господа на Шеше в окружении обитателей Вайкунтхи.','Здесь Враджа в последний раз провожал Кришну; разлука гопи с Господом, начавшаяся на этом гхате, стала вечной темой бхакти.','[{"name": "Акрура", "q": "Акрура"}, {"name": "Шри Кришна", "q": "Кришна"}, {"name": "Господь Баларама", "q": "Баларама"}]','Akrur Ghat Vrindavan',NULL,30),
('yogapitha','navadvipa','antardvipa','Йогапитха','Yogapīṭha','place',23.4242,88.388,'Место явления Шри Чайтаньи Махапрабху','Священное место рождения Господа Гауранги — дом Джаганнатхи Мишры и Шачидеви. Здесь восстановлен дом семьи с божествами младенца Нимая на коленях родителей и древо нима, под которым Он явился.','В вечер полнолуния Пхалгуна, во время лунного затмения, когда вся Бенгалия пела имена Господа, в этом дворе явился Гауранга Махапрабху.','[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}, {"name": "Шачимата", "q": "Шачи"}, {"name": "Джаганнатха Мишра", "q": "Джаганнатха Мишра"}]','Yogapith Mayapur',NULL,0),
('srivasa-angan','navadvipa','antardvipa','Шриваса-ангана','Śrīvāsa Aṅgana','place',23.4235,88.3886,'Двор ночной санкиртаны Махапрабху','Двор дома Шривасы Тхакура, где Гауранга Махапрабху с приближёнными каждую ночь пел святые имена за закрытыми дверями. Здесь Господь явил Свой облик Верховной Личности (сапта-прахария-бхава).','В этих ночных киртанах рождалось движение санкиртаны; здесь Махапрабху благословлял преданных и являл Свои сокровенные настроения.','[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}, {"name": "Шриваса Тхакур", "q": "Шриваса"}, {"name": "Нитьянанда Прабху", "q": "Нитьянанда"}, {"name": "Адвайта Ачарья", "q": "Адвайта Ачарья"}, {"name": "Гададхара Пандит", "q": "Гададхара"}]','Srivas Angan Mayapur',NULL,1),
('chand-kazi','navadvipa','antardvipa','Самадхи Чанда Кази','Cānd Kājī Samādhi','samadhi',23.4108,88.395,'Магометанский судья, обращённый Махапрабху','Самадхи мусульманского судьи Чанда Кази, запретившего было киртан. Когда Махапрабху повёл многотысячное шествие с пением к его дому, Кази смягчился, осознал величие святого имени и стал преданным.','Эта победа санкиртаны над запретом — первое в истории движение гражданского неповиновения во имя Бога, явленное Господом Гаурангой.','[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}, {"name": "Нитьянанда Прабху", "q": "Нитьянанда"}]','Chand Kazi Samadhi Mayapur',NULL,2),
('tovp','navadvipa','antardvipa','Храм Ведического Планетария (ИСККОН)','TOVP','temple',23.4258,88.3882,'Всемирная штаб-квартира ИСККОН в Маяпуре','Величественный храм Шри Маяпур-Чандродая, основанный Шрилой Прабхупадой, с грандиозным куполом и Храмом Ведического Планетария. Здесь поклоняются Панча-таттве, Радха-Мадхаве и Нрисимхадеву; рядом — самадхи Бхактисиддханты Сарасвати.',NULL,'[{"name": "Шрила Прабхупада", "q": "Прабхупада"}, {"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Temple of the Vedic Planetarium Mayapur',NULL,3),
('simantadvipa','navadvipa','islands','Симантадвипа','Sīmantadvīpa','island',23.44,88.39,'Слушание (шравана) · остров Симантини-деви','Остров, олицетворяющий шравану — слушание о Господе. Здесь богиня Парвати (Симантини-деви) посыпала пробор пылью с этой земли, услышав о грядущем явлении Гауранги.',NULL,'[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Simantadwip Mayapur',NULL,4),
('godrumadvipa','navadvipa','islands','Годрумадвипа','Godrumadvīpa','island',23.405,88.37,'Воспевание (киртана) · кунджа Бхактивиноды','Остров киртаны. Здесь, в Сурабхи-кундже, медитировал Бхактивинода Тхакур, возродивший в XIX веке славу дхамы. Это олицетворение пения святого имени.',NULL,'[{"name": "Бхактивинода Тхакур", "q": "Бхактивинода"}, {"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Godrumadwip Mayapur',NULL,5),
('madhyadvipa','navadvipa','islands','Мадхьядвипа','Madhyadvīpa','island',23.395,88.405,'Памятование (смарана) · обитель семи мудрецов','Срединный остров, олицетворяющий смарану — памятование о Господе. Связан с Наймишараньей и семью мудрецами (сапта-риши), которые медитировали здесь на Гаурангу.',NULL,'[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Madhyadwip Mayapur',NULL,6),
('koladvipa','navadvipa','koladvipa','Коладвипа (Навадвипа-город)','Koladvīpa','island',23.409,88.368,'Служение стопам (пада-севана) · Кулия','Большой остров за Гангой, где стоит современный город Навадвипа. Здесь, в Кулии, Махапрабху прощал оскорбления (апарадха-бханджана), а ныне находится храм Дхамешвара Махапрабху с Его домашним божеством.','В Кулии Господь явил Свою всепрощающую милость, освободив даже тех, кто прежде хулил преданных.','[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}, {"name": "Нитьянанда Прабху", "q": "Нитьянанда"}]','Navadvipa town West Bengal',NULL,7),
('ritudvipa','navadvipa','islands','Ритудвипа','Ṛtudvīpa','island',23.415,88.4,'Поклонение (арчана) · игры Радхи и Кришны','Остров арчаны — храмового поклонения. Считается, что здесь, в настроении Враджа, проявляются игры Радхи и Кришны внутри Гауранга Лилы.',NULL,'[{"name": "Шримати Радхарани", "q": "Радхарани"}, {"name": "Шри Кришна", "q": "Кришна"}, {"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Ritudwip Navadvipa',NULL,8),
('jahnudvipa','navadvipa','islands','Джахнудвипа','Jahnudvīpa','island',23.385,88.415,'Молитва (вандана) · обитель Джахну Муни','Остров ванданы — вознесения молитв. Назван в честь мудреца Джахну, который, по преданию, выпил Гангу и вновь выпустил её, отчего река зовётся Джахнави.',NULL,'[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Jahnudwip Navadvipa',NULL,9),
('modadrumadvipa','navadvipa','islands','Модадрумадвипа','Modadrumadvīpa','island',23.435,88.41,'Служение (дасья) · родина Вриндавана даса','Остров дасьи — служения Господу. В Мамгачи здесь явился Вриндаван дас Тхакур, автор «Чайтанья-бхагаваты»; связан также с играми Господа Рамачандры.',NULL,'[{"name": "Вриндаван дас Тхакур", "q": "Вриндаван дас"}, {"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Modadrumadwip Navadvipa',NULL,10),
('rudradvipa','navadvipa','islands','Рудрадвипа','Rudradvīpa','island',23.418,88.382,'Дружба (сакхья) · остров одиннадцати Рудр','Остров сакхьи — дружеского служения. Здесь одиннадцать Рудр (форм Шивы) пели и танцевали в восторге, предвкушая явление Господа Гауранги.',NULL,'[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Rudradwip Navadvipa',NULL,11),
('jagannath-mandir','nilachala','core','Шри Джаганнатха-мандир','Jagannātha Mandira','temple',19.8048,85.818,'Великий храм Господа вселенной','Один из величайших храмов Индии, возведённый в XII веке. На алтаре — Джаганнатха, Баладева и Субхадра с диском Сударшаной. Шри Кришна Чайтанья Махапрабху ежедневно приходил сюда на даршан, охваченный экстатической любовью.','Перед колесницей Джаганнатхи на Ратха-ятре Махапрабху пел и танцевал так, что Господь, согласно преданию, замедлял ход, внимая Его любви.','[{"name": "Господь Джаганнатха", "q": "Джаганнатха"}, {"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}, {"name": "Господь Баларама", "q": "Баларама"}]','Jagannath Temple Puri',NULL,0),
('gundicha','nilachala','core','Гундича-мандир','Guṇḍicā Mandira','temple',19.8155,85.833,'«Вриндаван» Пури — цель Ратха-ятры','Храм в трёх километрах от главного, куда на Ратха-ятре привозят Джаганнатху. Гундича олицетворяет Вриндаван — встречу Кришны с жителями Враджа. Накануне праздника Махапрабху Сам мыл этот храм (Гундича-марджана).','Уборка Гундичи, которую Господь возглавлял с преданными, символизирует очищение сердца для приёма Кришны.','[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}, {"name": "Господь Джаганнатха", "q": "Джаганнатха"}]','Gundicha Temple Puri',NULL,1),
('narendra-sarovara','nilachala','core','Нарендра-саровара','Narendra-sarovara','kunda',19.817,85.8265,'Озеро праздника Чандана-ятры','Священное озеро, где проходит Чандана-ятра — катание божеств на лодках. Здесь Шри Кришна Чайтанья Махапрабху с преданными совершал водные игры (джала-кели), вспоминая лодочные забавы Кришны на Ямуне.',NULL,'[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}, {"name": "Господь Джаганнатха", "q": "Джаганнатха"}]','Narendra Sarovar Puri',NULL,2),
('gambhira','nilachala','chaitanya','Гамбхира (Радха-Канта матх)','Gambhīrā','place',19.806,85.8205,'Покои, где Махапрабху прожил 18 лет','Комната в доме Кашия Мишры, где последние восемнадцать лет жил Шри Кришна Чайтанья Махапрабху. В этих стенах Он переживал глубочайшие настроения любви в разлуке; сохранились Его деревянная сандалия и сосуд для воды.','По ночам в Гамбхире Господь, охваченный разлукой с Кришной, в экстазе протискивался сквозь прутья и тёрся лицом о камни.','[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}, {"name": "Рамананда Рай", "q": "Рамананда Рай"}, {"name": "Сарвабхаума Бхаттачарья", "q": "Сарвабхаума"}]','Gambhira Radha Kanta Math Puri',NULL,3),
('tota-gopinatha','nilachala','chaitanya','Тота-Гопинатха','Ṭoṭā-Gopīnātha','temple',19.7995,85.824,'Сидящее божество Гопинатхи Гададхары','Храм сидящего божества Гопинатхи в саду (тота), которому поклонялся Гададхара Пандит. По преданию, именно здесь Шри Кришна Чайтанья Махапрабху завершил Свои земные игры, войдя в это божество.',NULL,'[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}, {"name": "Гададхара Пандит", "q": "Гададхара"}]','Tota Gopinath Temple Puri',NULL,4),
('siddha-bakula','nilachala','chaitanya','Сиддха-бакула','Siddha-bakula','samadhi',19.8085,85.822,'Бхаджан-кутир и самадхи Харидаса Тхакура','Место, где жил и повторял по триста тысяч имён в день Намачарья Харидас Тхакур. Дерево бакула, по преданию, выросло из зубочистки, посаженной Махапрабху. Здесь — самадхи Харидаса.','Когда Харидас покинул тело, Шри Кришна Чайтанья Махапрабху Сам нёс его и танцевал в санкиртане, своими руками совершив погребение у моря.','[{"name": "Харидас Тхакур", "q": "Харидас"}, {"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Siddha Bakula Puri',NULL,5),
('sarvabhauma-house','nilachala','chaitanya','Дом Сарвабхаумы Бхаттачарьи','Sārvabhauma','place',19.8052,85.817,'Великий учёный, покорённый Махапрабху','Место, связанное с Сарвабхаумой Бхаттачарьей — прославленным знатоком веданты Пури. Встретив Шри Чайтанью, он оставил сухое философствование и стал великим преданным, сложив сто стихов во славу Господа.',NULL,'[{"name": "Сарвабхаума Бхаттачарья", "q": "Сарвабхаума"}, {"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}, {"name": "Махараджа Пратапарудра", "q": "Пратапарудра"}]','Jagannath Temple Puri',NULL,6),
('samudra-sangama','nilachala','around','Самудра (Сваргадвар)','Samudra','river',19.7935,85.824,'Берег моря, где Махапрабху искал Кришну','Берег Бенгальского залива у Сваргадвара. Приняв синие воды моря за Ямуну, Шри Кришна Чайтанья Махапрабху в экстазе бросился в волны; преданные нашли Его вдали, унесённого приливом.','Однажды волны вынесли потерявшего сознание Господа к рыбаку, решившему, что поймал духа; так глубока была погружённость Махапрабху в любовь.','[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Swargadwar Beach Puri',NULL,7),
('atharanala','nilachala','around','Атхаранала','Aṭhāranālā','place',19.823,85.829,'Древний мост — врата Пури','Старинный каменный мост на восемнадцать пролётов у въезда в Пури. Здесь, впервые увидев издали купол храма Джаганнатхи, Шри Кришна Чайтанья Махапрабху упал без чувств от любви.',NULL,'[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Atharanala Bridge Puri',NULL,8),
('alalanatha','nilachala','around','Алаланатха (Брахмагири)','Ālālanātha','temple',19.867,85.756,'Камень, расплавившийся от любви Господа','Храм Господа Алаланатхи (Вишну) близ Пури. Распростёршись в поклоне на каменном полу, Шри Кришна Чайтанья Махапрабху в экстазе размягчил камень, оставив на нём отпечаток Своего тела.',NULL,'[{"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Alarnath Temple Brahmagiri',NULL,9),
('sakshi-gopala','nilachala','around','Сакши-Гопала','Sākṣī-Gopāla','temple',19.946,85.7,'Гопала, ставший свидетелем обещания','Храм божества Гопалы между Пури и Бхубанешваром. По знаменитому преданию, это божество прошло из Вриндавана, чтобы засвидетельствовать обещание, данное одним брахманом другому. Шри Кришна Чайтанья Махапрабху с радостью рассказывал эту историю.',NULL,'[{"name": "Шри Кришна", "q": "Кришна"}, {"name": "Гауранга Махапрабху", "q": "Чайтанья Махапрабху"}]','Sakshi Gopal Temple Odisha',NULL,10);
